10	// reportedWorkersAdapter adapts the in-memory worker_ingest registry to the
11	// ddxgraphql.ReportedWorkersProvider interface used by the reportedWorkers
12	// query. now is overridable so tests can advance the freshness clock without
13	// mutating registry timestamps.
14	type reportedWorkersAdapter struct {
15		reg *workerIngestRegistry
16		mu  sync.RWMutex
17		now func() time.Time
18	}
19	
20	func newReportedWorkersAdapter(reg *workerIngestRegistry) *reportedWorkersAdapter {
21		return &reportedWorkersAdapter{reg: reg, now: func() time.Time { return time.Now().UTC() }}
22	}
23	
24	func (a *reportedWorkersAdapter) currentNow() time.Time {
25		a.mu.RLock()
26		defer a.mu.RUnlock()
27		return a.now()
28	}
29	
30	// GetReportedWorkers implements ddxgraphql.ReportedWorkersProvider.
31	func (a *reportedWorkersAdapter) GetReportedWorkers() []*ddxgraphql.ReportedWorker {
32		if a.reg == nil {
33			return nil
34		}
35		now := a.currentNow()
36		snap := a.reg.snapshot()
37		out := make([]*ddxgraphql.ReportedWorker, 0, len(snap))
38		for _, rec := range snap {
39			w := &ddxgraphql.ReportedWorker{
40				ID:                  rec.WorkerID,
41				Project:             rec.Identity.ProjectRoot,
42				Harness:             rec.Identity.Harness,
43				State:               freshnessState(rec, now),
44				LastEventAt:         rec.LastEventAt.UTC().Format(time.RFC3339Nano),
45				MirrorFailuresCount: rec.MirrorFailuresCount,
46				HadDroppedBackfill:  rec.HadDroppedBackfill,
47			}
48			if rec.CurrentBead != "" {
49				cb := rec.CurrentBead
50				w.CurrentBead = &cb
51			}
52			if rec.CurrentAttempt != "" {
53				ca := rec.CurrentAttempt
54				w.CurrentAttempt = &ca
55			}
56			out = append(out, w)
57		}
58		return out
59	}
