94	func normalizeRunState(state RunState) RunState {
95		now := time.Now().UTC()
96		if state.StartedAt.IsZero() {
97			state.StartedAt = now
98		}
99		if state.RefreshedAt.IsZero() {
100			state.RefreshedAt = now
101		}
102		if state.ExpiresAt.IsZero() {
103			state.ExpiresAt = state.RefreshedAt.Add(RunStateLivenessTTL)
104		}
105		if state.PID == 0 {
106			state.PID = os.Getpid()
107		}
108		return state
109	}
