21	// postLoopback sends a JSON POST to path with body and returns the recorder.
22	// Sets the loopback RemoteAddr so the requireTrusted gate passes.
23	func postLoopback(t *testing.T, srv *Server, path string, body any) *httptest.ResponseRecorder {
24		t.Helper()
25		var buf bytes.Buffer
26		if body != nil {
27			if err := json.NewEncoder(&buf).Encode(body); err != nil {
28				t.Fatalf("encode body: %v", err)
29			}
30		}
31		req := httptest.NewRequest(http.MethodPost, path, &buf)
32		req.Header.Set("Content-Type", "application/json")
33		req.RemoteAddr = "127.0.0.1:54321"
34		w := httptest.NewRecorder()
35		srv.Handler().ServeHTTP(w, req)
36		return w
37	}
