41	func readWorkerEventsLog(t *testing.T, workingDir string) []loggedEvent {
42		t.Helper()
43		path := filepath.Join(workingDir, ddxroot.DirName, "server", "worker-events.jsonl")
44		f, err := os.Open(path)
45		if err != nil {
46			if os.IsNotExist(err) {
47				return nil
48			}
49			t.Fatalf("open events log: %v", err)
50		}
51		defer f.Close()
52		var out []loggedEvent
53		sc := bufio.NewScanner(f)
54		for sc.Scan() {
55			var ev loggedEvent
56			if err := json.Unmarshal(sc.Bytes(), &ev); err != nil {
57				t.Fatalf("decode log line %q: %v", sc.Text(), err)
58			}
59			out = append(out, ev)
60		}
61		if err := sc.Err(); err != nil {
62			t.Fatalf("scan log: %v", err)
63		}
64		return out
65	}
