209	// childEnvVar is set on the subprocess invocation of
210	// TestHelperPostRegisterChild and carries the URL of the parent's
211	// httptest.Server. Its presence is what activates the child code path; if
212	// unset the child test simply skips so a normal `go test ./...` run is a
213	// no-op for the helper.
214	const childEnvVar = "DDX_INGESTION_E2E_REGISTER_URL"
