216	// TestServerIngestion_RealWorkerCanRegister is the wired-in integration
217	// proof for ADR-022 step 1: it stands up the production HTTP path
218	// (httptest.Server wrapping srv.Handler() — same mux, same requireTrusted
219	// gate, same handler, real TCP socket) and then re-execs the test binary as
220	// a subprocess to POST /api/workers/register over the network. The
221	// assertion is on the parent's in-memory registry, proving the round-trip
222	// from a real external HTTP client landed in the worker view.
223	func TestServerIngestion_RealWorkerCanRegister(t *testing.T) {
224		if os.Getenv(childEnvVar) != "" {
225			// Defensive: should never happen because the child invocation runs
226			// only TestHelperPostRegisterChild, but if a future test runner
227			// fans out differently we don't want this test to spin up its own
228			// nested subprocess.
229			t.Skip("child invocation; covered by TestHelperPostRegisterChild")
230		}
231		dir := setupTestDir(t)
232		srv := New(":0", dir)
233		ts := httptest.NewServer(srv.Handler())
234		defer ts.Close()
235	
236		cmd := exec.Command(os.Args[0],
237			"-test.run", "^TestHelperPostRegisterChild$",
238			"-test.v",
239			"-test.count=1",
240			"-test.timeout=30s",
241		)
242		cmd.Env = append(os.Environ(), childEnvVar+"="+ts.URL)
243		out, err := cmd.CombinedOutput()
244		if err != nil {
245			t.Fatalf("subprocess failed: %v\n%s", err, out)
246		}
247	
248		deadline := time.Now().Add(2 * time.Second)
249		var snap []*workerRecord
250		for time.Now().Before(deadline) {
251			snap = srv.workerIngest.snapshot()
252			if len(snap) == 1 {
253				break
254			}
255			time.Sleep(20 * time.Millisecond)
256		}
257		if len(snap) != 1 {
258			t.Fatalf("registry size: got %d, want 1; subprocess output:\n%s", len(snap), out)
259		}
260		rec := snap[0]
261		if rec.Identity.Harness != "subprocess-harness" {
262			t.Errorf("identity.harness: got %q, want subprocess-harness", rec.Identity.Harness)
263		}
264		if rec.Identity.ExecutorHost != "subprocess-host" {
265			t.Errorf("identity.executor_host: got %q, want subprocess-host", rec.Identity.ExecutorHost)
266		}
267		if rec.WorkerID == "" || !strings.HasPrefix(rec.WorkerID, "wkr-") {
268			t.Errorf("worker_id %q missing wkr- prefix", rec.WorkerID)
269		}
270		if rec.RegisteredAt.IsZero() {
271			t.Error("RegisteredAt unset")
272		}
273	}
