275	// TestHelperPostRegisterChild is the subprocess half of
276	// TestServerIngestion_RealWorkerCanRegister. It is a normal-looking Go
277	// test that no-ops unless re-invoked with childEnvVar set, in which case
278	// it performs a real net/http POST against the parent's httptest.Server.
279	func TestHelperPostRegisterChild(t *testing.T) {
280		url := os.Getenv(childEnvVar)
