302			t.Fatalf("status=%d body=%s", resp.StatusCode, respBody)
303		}
304		var out struct {
305			WorkerID string `json:"worker_id"`
306		}
307		if err := json.Unmarshal(respBody, &out); err != nil {
308			t.Fatalf("decode response %q: %v", respBody, err)
309		}
310		if out.WorkerID == "" {
311			t.Fatal("empty worker_id in response")
312		}
313		fmt.Printf("subprocess registered worker_id=%s\n", out.WorkerID)
314	}
