// snapshot returns a copy of the registry for read-only inspection (tests
// and future GraphQL consumers). The returned slice is a stable copy; the
// records themselves are pointers into the registry and must be treated
// as read-only. Stale (disconnected) entries are evicted before the snapshot.
func (r *workerIngestRegistry) snapshot() []*workerRecord {
	r.mu.Lock()
	defer r.mu.Unlock()
	r.reapDisconnected()
	out := make([]*workerRecord, 0, len(r.workers))
	for _, rec := range r.workers {
		copy := *rec
		out = append(out, &copy)
	}
	return out
}

// reapDisconnected removes workers past the disconnected TTL (>10× probe interval).
// Must be called with r.mu held.
func (r *workerIngestRegistry) reapDisconnected() {
	const probeInterval = 30 * time.Second
	const disconnectedTTL = 10 * probeInterval
	now := time.Now().UTC()
	for id, rec := range r.workers {
		age := now.Sub(rec.LastEventAt)
		if age > disconnectedTTL {
			delete(r.workers, id)
		}
	}
}

