func TestWorkerIngest_ReapsDisconnected(t *testing.T) {
	dir := setupTestDir(t)
	srv := New(":0", dir)

	// Register two workers.
	id1 := registerWorker(t, srv, dir)
	id2 := registerWorker(t, srv, dir)

	snap := srv.workerIngest.snapshot()
	if len(snap) != 2 {
		t.Fatalf("initial snapshot: got %d, want 2", len(snap))
	}

	// Manually age id1's LastEventAt past the disconnected TTL (>10×30s = >300s).
	// We do this directly on the registry to simulate a stale worker.
	const probeInterval = 30 * time.Second
	const disconnectedTTL = 10 * probeInterval
	srv.workerIngest.mu.Lock()
	rec := srv.workerIngest.workers[id1]
	rec.LastEventAt = time.Now().UTC().Add(-(disconnectedTTL + 1*time.Second))
	srv.workerIngest.mu.Unlock()

	// Call snapshot() which should reap the stale worker.
	snap = srv.workerIngest.snapshot()
	if len(snap) != 1 {
		t.Fatalf("snapshot after age: got %d workers, want 1 (id1 should be reaped)", len(snap))
	}
	if snap[0].WorkerID != id2 {
		t.Errorf("remaining worker: got %q, want %q", snap[0].WorkerID, id2)
	}
}

