56	// GetBeadSnapshots implements ddxgraphql.StateProvider.
57	//
58	// When projectID is non-empty this delegates to GetBeadSnapshotsForProject so
59	// the resolver path opens exactly one project's store; a scoped query never
60	// pays the N-project scan cost (ddx-9ce6842a Part 2 step 1). When projectID is
61	// empty every registered project is scanned — that is still O(projects) by
62	// necessity, but each project's bead.Store receives a pushed-down filter so
63	// non-matching beads are never materialized as BeadSnapshot values.
64	func (s *ServerState) GetBeadSnapshots(status, label, projectID, search string) []ddxgraphql.BeadSnapshot {
65		if projectID != "" {
66			return s.GetBeadSnapshotsForProject(projectID, status, label, search)
67		}
68		projects := s.GetProjects()
69		pred := beadFilterPredicate(status, label, search)
70		var result []ddxgraphql.BeadSnapshot
71		for _, proj := range projects {
72			result = append(result, s.beadSnapshotsForProjectEntry(proj, pred)...)
73		}
