77	// GetBeadSnapshotsForProject implements ddxgraphql.StateProvider. It opens
78	// exactly one project's bead store — iteration over other projects is not
79	// performed for any reason, so the cross-project loop cost is avoided for the
80	// common per-project bead list.
81	func (s *ServerState) GetBeadSnapshotsForProject(projectID, status, label, search string) []ddxgraphql.BeadSnapshot {
82		if projectID == "" {
83			return nil
84		}
85		proj, ok := s.GetProjectByID(projectID)
86		if !ok {
87			return nil
88		}
89		pred := beadFilterPredicate(status, label, search)
90		return s.beadSnapshotsForProjectEntry(proj, pred)
