94	// beadSnapshotsForProjectEntry invokes it with the project path it is about
95	// to open. Tests use this to assert that the scoped path opens exactly one
96	// project's store (ddx-9ce6842a AC §3).
97	var beadStoreOpenHook func(projectPath string)
