99	// beadSnapshotsForProjectEntry reads the single project's bead store, applies
100	// the (possibly nil) predicate at the store layer (filter pushdown), and
101	// returns GraphQL snapshots for the matching beads. Callers are responsible
102	// for deciding which projects to pass through — this helper never touches any
103	// other project's state.
104	func (s *ServerState) beadSnapshotsForProjectEntry(proj ProjectEntry, pred func(bead.Bead) bool) []ddxgraphql.BeadSnapshot {
105		if beadStoreOpenHook != nil {
106			beadStoreOpenHook(proj.Path)
107		}
108		store := bead.NewStore(ddxroot.JoinProject(proj.Path))
109		beads, err := store.ReadAllFiltered(pred)
110		if err != nil {
