121	// beadFilterPredicate returns a predicate suitable for bead.Store.ReadAllFiltered
122	// that applies status/label/search filters. A nil return means "match all".
123	func beadFilterPredicate(status, label, search string) func(bead.Bead) bool {
124		if status == "" && label == "" && search == "" {
125			return nil
126		}
127		q := strings.ToLower(search)
128		return func(b bead.Bead) bool {
129			if status != "" && b.Status != status {
130				return false
131			}
132			if label != "" && !containsString(b.Labels, label) {
133				return false
134			}
135			if q != "" {
136				if !strings.Contains(strings.ToLower(b.ID), q) && !strings.Contains(strings.ToLower(b.Title), q) {
