265	// WorkerRecord stores the project's filesystem path in ProjectRoot, but the
266	// GraphQL argument is a project id (e.g. proj-96d7ea83). Resolve the id to a
267	// path via the project registry before filtering so the two representations
268	// match; previously this compared id→path directly and filtered out every
269	// worker on per-project queries.
270	func (s *ServerState) GetWorkersGraphQL(projectID string) []*ddxgraphql.Worker {
271		if s.workingDir == "" {
272			return nil
273		}
274		expectedPath := ""
275		if projectID != "" {
276			proj, ok := s.GetProjectByID(projectID)
277			if !ok {
278				return nil
279			}
280			expectedPath = proj.Path
281		}
282		workersDir := ddxroot.JoinProject(s.workingDir, "workers")
283		entries, err := os.ReadDir(workersDir)
284		if err != nil {
285			return nil
286		}
287		var out []*ddxgraphql.Worker
288		for _, entry := range entries {
289			if !entry.IsDir() {
290				continue
291			}
292			data, err := os.ReadFile(filepath.Join(workersDir, entry.Name(), "status.json"))
293			if err != nil {
294				continue
295			}
296			var rec WorkerRecord
297			if err := json.Unmarshal(data, &rec); err != nil {
298				continue
299			}
300			if expectedPath != "" && rec.ProjectRoot != expectedPath {
301				continue
302			}
303			out = append(out, workerFromRecord(rec))
304		}
305		// Newest first.
306		sort.Slice(out, func(i, j int) bool {
307			si, sj := out[i].StartedAt, out[j].StartedAt
308			if si == nil || sj == nil {
309				return si != nil
310			}
311			ti, _ := time.Parse(time.RFC3339, *si)
312			tj, _ := time.Parse(time.RFC3339, *sj)
313			return ti.After(tj)
314		})
315		return out
316	}
