397	// workerFromRecord converts a WorkerRecord to the GraphQL Worker type.
398	func workerFromRecord(rec WorkerRecord) *ddxgraphql.Worker {
399		attempts := rec.Attempts
400		successes := rec.Successes
401		failures := rec.Failures
402		w := &ddxgraphql.Worker{
403			ID:           rec.ID,
404			Kind:         rec.Kind,
405			State:        rec.State,
406			ProjectRoot:  rec.ProjectRoot,
407			Attempts:     &attempts,
408			Successes:    &successes,
409			Failures:     &failures,
410			RecentEvents: []*ddxgraphql.WorkerRecentEvent{},
411		}
412		if rec.Status != "" {
413			w.Status = &rec.Status
414		}
415		if rec.Harness != "" {
416			w.Harness = &rec.Harness
417		}
418		if rec.Provider != "" {
419			w.Provider = &rec.Provider
420		}
421		if rec.Model != "" {
422			w.Model = &rec.Model
423		}
424		if rec.Effort != "" {
425			w.Effort = &rec.Effort
426		}
427		if rec.Once {
428			b := true
429			w.Once = &b
430		}
431		if rec.PollInterval != "" {
432			w.PollInterval = &rec.PollInterval
433		}
434		if !rec.StartedAt.IsZero() {
435			s := rec.StartedAt.UTC().Format(time.RFC3339)
436			w.StartedAt = &s
437		}
438		if !rec.FinishedAt.IsZero() {
439			s := rec.FinishedAt.UTC().Format(time.RFC3339)
440			w.FinishedAt = &s
441		}
442		if rec.Error != "" {
443			w.Error = &rec.Error
444		}
445		if rec.StdoutPath != "" {
446			w.StdoutPath = &rec.StdoutPath
447		}
448		if rec.SpecPath != "" {
449			w.SpecPath = &rec.SpecPath
450		}
451		if rec.CurrentBead != "" {
452			w.CurrentBead = &rec.CurrentBead
453		}
454		if rec.LastError != "" {
455			w.LastError = &rec.LastError
456		}
457		if rec.LastResult != nil {
458			w.LastResult = workerResultFromRecord(rec.LastResult)
459		}
460		if rec.CurrentAttempt != nil {
461			w.CurrentAttempt = currentAttemptFromRecord(rec.CurrentAttempt)
462		}
463		for _, p := range rec.RecentPhases {
464			pt := p // copy
465			w.RecentPhases = append(w.RecentPhases, &ddxgraphql.PhaseTransition{
466				Phase:    pt.Phase,
467				Ts:       pt.TS.UTC().Format(time.RFC3339),
468				PhaseSeq: pt.PhaseSeq,
469			})
470		}
471		for _, e := range rec.Lifecycle {
472			ev := e
473			gqlEvent := &ddxgraphql.WorkerLifecycleEvent{
474				Action:    ev.Action,
475				Actor:     ev.Actor,
476				Timestamp: ev.Timestamp.UTC().Format(time.RFC3339),
477			}
478			if ev.Detail != "" {
479				gqlEvent.Detail = &ev.Detail
480			}
481			if ev.BeadID != "" {
482				gqlEvent.BeadID = &ev.BeadID
483			}
484			w.LifecycleEvents = append(w.LifecycleEvents, gqlEvent)
485		}
486		if rec.LastAttempt != nil {
487			w.LastAttempt = lastAttemptFromRecord(rec.LastAttempt)
488		}
489		if rec.LandSummary != nil {
490			w.LandSummary = landSummaryFromRecord(rec.LandSummary)
491		}
492		return w
493	}
