679	// GetSessionsCostSummaryGraphQL implements ddxgraphql.StateProvider.
680	// It reads exactly the requested project's monthly session shards.
681	func (s *ServerState) GetSessionsCostSummaryGraphQL(projectID string, since, until *time.Time) *ddxgraphql.SessionsCostSummary {
682		proj, ok := s.GetProjectByID(projectID)
683		if !ok {
684			return &ddxgraphql.SessionsCostSummary{}
685		}
686		logDir := agent.SessionLogDirForWorkDir(proj.Path)
687		entries, err := agent.ReadSessionIndex(logDir, agent.SessionIndexQuery{
688			StartedAfter:  since,
689			StartedBefore: until,
690		})
691		if err != nil {
692			return &ddxgraphql.SessionsCostSummary{}
693		}
694		summary := &ddxgraphql.SessionsCostSummary{}
695		var localTokens int
696		for _, e := range entries {
697			mode := e.BillingMode
698			if mode == "" {
699				mode = agent.BillingModeFor(e.Harness, e.Surface, e.BaseURL)
700			}
701			switch mode {
702			case agent.BillingModePaid:
703				summary.CashUsd += e.CostUSD
704			case agent.BillingModeSubscription:
705				summary.SubscriptionEquivUsd += e.CostUSD
706			case agent.BillingModeLocal:
707				summary.LocalSessionCount++
708				tokens := e.Tokens
709				if tokens == 0 {
710					tokens = e.InputTokens + e.OutputTokens
711				}
712				localTokens += tokens
713			}
714		}
715		if rate := localCostPer1KTokens(proj.Path); rate != nil {
716			estimate := *rate * float64(localTokens) / 1000
717			summary.LocalEstimatedUsd = &estimate
718		}
719		return summary
720	}
