722	// readProjectSessions reads monthly session shards for one project and maps to graphql types.
723	func readProjectSessions(proj ProjectEntry, provider string, startedAfter, startedBefore *time.Time) []*ddxgraphql.AgentSession {
724		logDir := agent.SessionLogDirForWorkDir(proj.Path)
725		entries, err := agent.ReadSessionIndex(logDir, agent.SessionIndexQuery{
726			StartedAfter:  startedAfter,
727			StartedBefore: startedBefore,
728			Provider:      provider,
729			DefaultRecent: startedAfter == nil && startedBefore == nil,
730		})
731		if err != nil {
732			return nil
733		}
734		out := make([]*ddxgraphql.AgentSession, 0, len(entries))
735		for _, e := range entries {
736			sess := agentSessionFromIndex(proj.ID, e)
737			out = append(out, sess)
738		}
739		return out
740	}
