742	func localCostPer1KTokens(projectRoot string) *float64 {
743		cfg, err := config.LoadWithWorkingDir(projectRoot)
744		if err != nil || cfg.Cost == nil || cfg.Cost.LocalPer1KTokens == nil {
745			return nil
746		}
747		rate := *cfg.Cost.LocalPer1KTokens
748		return &rate
749	}
750	
751	func agentSessionFromIndex(projectID string, e agent.SessionIndexEntry) *ddxgraphql.AgentSession {
752		billingMode := e.BillingMode
753		if billingMode == "" {
754			billingMode = agent.BillingModeFor(e.Harness, e.Surface, e.BaseURL)
755		}
756		sess := &ddxgraphql.AgentSession{
757			ID:          e.ID,
758			ProjectID:   projectID,
759			Harness:     e.Harness,
760			Provider:    providerPtr(e.Provider),
761			Model:       e.Model,
762			Effort:      e.Effort,
763			DurationMs:  e.DurationMS,
764			StartedAt:   e.StartedAt.UTC().Format(time.RFC3339),
765			BillingMode: billingMode,
766		}
767	
768		// Derive status and outcome from exit code / error.
769		if e.ExitCode != 0 || e.Outcome == "failure" {
770			sess.Status = "failed"
771			outcome := "failure"
772			sess.Outcome = &outcome
773			if e.Detail != "" {
774				sess.Detail = &e.Detail
775			}
776		} else {
777			sess.Status = "completed"
778			outcome := "success"
779			sess.Outcome = &outcome
780		}
781	
782		// EndedAt = StartedAt + duration.
783		if !e.EndedAt.IsZero() {
784			endedAt := e.EndedAt.UTC().Format(time.RFC3339)
785			sess.EndedAt = &endedAt
786		} else if e.DurationMS > 0 {
787			endedAt := e.StartedAt.Add(time.Duration(e.DurationMS) * time.Millisecond).UTC().Format(time.RFC3339)
788			sess.EndedAt = &endedAt
789		}
790	
791		if e.CostUSD > 0 {
792			sess.Cost = &e.CostUSD
793		}
794	
795		// Token breakdown.
796		if e.InputTokens > 0 || e.OutputTokens > 0 || e.Tokens > 0 {
797			prompt := e.InputTokens
798			completion := e.OutputTokens
799			total := e.Tokens
800			sess.Tokens = &ddxgraphql.TokenUsage{
801				Prompt:     &prompt,
802				Completion: &completion,
803				Total:      &total,
804			}
805		}
806	
807		if e.BeadID != "" {
808			sess.BeadID = &e.BeadID
809		}
810		if e.WorkerID != "" {
811			sess.WorkerID = &e.WorkerID
812		}
813		if e.NativeLogRef != "" {
814			sess.StdoutPath = &e.NativeLogRef
815		}
816		if e.BaseRev != "" {
817			sess.BaseRev = &e.BaseRev
818		}
819		if e.ResultRev != "" {
820			sess.ResultRev = &e.ResultRev
821		}
822		return sess
823	}
