111	// WriteRunState atomically writes state to a per-attempt file under
112	// .ddx/run-state/ and refreshes .ddx/run-state.json as a legacy compatibility
113	// summary. Writes go to sibling tmp files and are then renamed into place so
114	// readers never observe a partial record.
115	func WriteRunState(projectRoot string, state RunState) error {
116		if projectRoot == "" {
117			return errors.New("WriteRunState: projectRoot is empty")
118		}
119		state = normalizeRunState(state)
120		attemptPath, err := runStateAttemptPath(projectRoot, state.AttemptID)
121		if err != nil {
122			return err
123		}
124		ddxDir := ddxroot.JoinProject(projectRoot)
125		attemptDir := filepath.Dir(attemptPath)
126		if err := os.MkdirAll(ddxDir, 0o755); err != nil {
127			return fmt.Errorf("run-state: mkdir .ddx: %w", err)
128		}
129		if err := os.MkdirAll(attemptDir, 0o755); err != nil {
130			return fmt.Errorf("run-state: mkdir attempts: %w", err)
131		}
132		if err := writeRunStateJSON(attemptPath, state); err != nil {
133			return err
134		}
135		return writeRunStateJSON(runStatePath(projectRoot), state)
136	}
137	
138	func writeRunStateJSON(final string, state RunState) error {
139		dir := filepath.Dir(final)
140		if err := os.MkdirAll(dir, 0o755); err != nil {
141			return fmt.Errorf("run-state: mkdir: %w", err)
142		}
143		data, err := json.MarshalIndent(state, "", "  ")
144		if err != nil {
145			return fmt.Errorf("run-state: marshal: %w", err)
146		}
147		data = append(data, '\n')
148	
149		tmp, err := os.CreateTemp(dir, "run-state-*.json.tmp")
150		if err != nil {
151			return fmt.Errorf("run-state: create tmp: %w", err)
152		}
153		tmpName := tmp.Name()
154		if _, err := tmp.Write(data); err != nil {
155			_ = tmp.Close()
156			_ = os.Remove(tmpName)
157			return fmt.Errorf("run-state: write tmp: %w", err)
158		}
159		if err := tmp.Close(); err != nil {
160			_ = os.Remove(tmpName)
161			return fmt.Errorf("run-state: close tmp: %w", err)
162		}
163		if err := os.Rename(tmpName, final); err != nil {
164			_ = os.Remove(tmpName)
165			return fmt.Errorf("run-state: rename: %w", err)
166		}
167		return nil
168	}
