239	func readRunStateAttemptFiles(projectRoot string) ([]RunState, error) {
240		dir, ok := existingRunStateDirPath(projectRoot)
241		if !ok {
242			return nil, nil
243		}
244		entries, err := os.ReadDir(dir)
245		if err != nil {
246			if os.IsNotExist(err) {
247				return nil, nil
248			}
249			return nil, err
250		}
251		var names []string
252		for _, entry := range entries {
253			if entry.IsDir() {
254				continue
255			}
256			name := entry.Name()
257			if !strings.HasSuffix(name, ".json") || strings.HasSuffix(name, ".tmp") {
258				continue
259			}
260			names = append(names, name)
261		}
262		sort.Strings(names)
263	
264		states := make([]RunState, 0, len(names))
265		for _, name := range names {
266			state, err := readRunStateFile(filepath.Join(dir, name))
267			if err != nil {
268				return nil, err
269			}
270			if state != nil {
271				states = append(states, *state)
272			}
273		}
274		return states, nil
275	}
