277	func latestRunState(states []RunState) (RunState, bool) {
278		if len(states) == 0 {
279			return RunState{}, false
280		}
281		latest := states[0]
282		for _, state := range states[1:] {
283			if runStateNewer(state, latest) {
284				latest = state
285			}
286		}
287		return latest, true
288	}
289	
290	func runStateNewer(a, b RunState) bool {
291		if !a.RefreshedAt.Equal(b.RefreshedAt) {
292			return a.RefreshedAt.After(b.RefreshedAt)
293		}
294		if !a.StartedAt.Equal(b.StartedAt) {
295			return a.StartedAt.After(b.StartedAt)
296		}
297		return a.AttemptID > b.AttemptID
298	}
